<?php namespace App\Repositories\Events;use App\Repositories\BaseRepository;use App\Models\Events\Event;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class EventRepository extends BaseRepository{    public function __construct(Event $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getUpcomingEvents(int $limit = 10): Collection    {        return $this->query()->where('start_date', '>=', now())->where('status', 'published')->orderBy('start_date', 'asc')->limit($limit)->get();    }    public function getOngoingEvents(): Collection    {        return $this->query()->where('start_date', '<=', now())->where('end_date', '>=', now())->where('status', 'published')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('start_date', [$startDate, $endDate])->orWhereBetween('end_date', [$startDate, $endDate])->get();    }    public function searchEvents(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->orWhere('venue', 'like', "%{$keyword}%")->get();    }    public function getByVenue(string $venue): Collection    {        return $this->findByField('venue', $venue);    }    public function getByOrganizer(string $organizer): Collection    {        return $this->findByField('organizer', $organizer);    }    public function getMonthlyEvents(int $year, int $month): Collection    {        return $this->query()->whereYear('start_date', $year)->whereMonth('start_date', $month)->where('status', 'published')->get();    }    public function publishEvent(int $id): bool    {        return $this->update($id, ['status' => 'published', 'published_at' => now()]);    }    public function cancelEvent(int $id, string $reason): bool    {        return $this->update($id, ['status' => 'cancelled', 'cancellation_reason' => $reason]);    }}